<template>
  <div class="setting-container">
    <el-card>
      <div slot="header" class="card-header">
        <span class="header-title">系统设置</span>
      </div>

      <el-form ref="settingForm" :model="form" :rules="rules" label-width="130px" class="setting-form">

        <!-- 基本信息设置 -->
        <div class="section">
          <div class="section-title">基本信息设置</div>
          <el-form-item label="商城名称" prop="shopName">
            <el-input v-model="form.shopName" placeholder="请输入商城名称" maxlength="50" show-word-limit></el-input>
          </el-form-item>
          <el-form-item label="Logo上传">
            <el-upload
              class="logo-uploader"
              action="#"
              :http-request="handleLogoUpload"
              :show-file-list="false"
              :before-upload="beforeLogoUpload"
            >
              <img v-if="form.logoUrl" :src="form.logoUrl" class="logo-img" alt="logo">
              <i v-else class="el-icon-plus logo-uploader-icon"></i>
            </el-upload>
            <div class="upload-tip">建议尺寸：200x200像素，支持JPG/PNG格式，大小不超过2MB</div>
          </el-form-item>
          <el-form-item label="客服电话" prop="servicePhone">
            <el-input v-model="form.servicePhone" placeholder="请输入客服电话" maxlength="20"></el-input>
          </el-form-item>
          <el-form-item label="工作时间" prop="workHours">
            <el-input v-model="form.workHours" placeholder="例如：周一至周五 09:00-18:00" maxlength="50"></el-input>
          </el-form-item>
        </div>

        <!-- 物流设置 -->
        <div class="section">
          <div class="section-title">物流设置</div>
          <el-form-item label="默认运费" prop="defaultShippingFee">
            <el-input-number v-model="form.defaultShippingFee" :precision="2" :min="0" :step="1" style="width:180px"></el-input-number>
            <span class="unit">元</span>
          </el-form-item>
          <el-form-item label="免邮门槛金额" prop="freeShippingThreshold">
            <el-input-number v-model="form.freeShippingThreshold" :precision="2" :min="0" :step="10" style="width:180px"></el-input-number>
            <span class="unit">元（0表示不设免邮）</span>
          </el-form-item>
        </div>

        <!-- 支付设置 -->
        <div class="section">
          <div class="section-title">支付设置</div>
          <el-form-item label="微信支付商户号" prop="mchId">
            <el-input
              v-model="form.mchId"
              type="password"
              placeholder="请输入微信支付商户号"
              show-password
              maxlength="32"
            ></el-input>
          </el-form-item>
          <el-form-item label="支付密钥" prop="paySecret">
            <el-input
              v-model="form.paySecret"
              type="password"
              placeholder="请输入支付密钥"
              show-password
              maxlength="64"
            ></el-input>
          </el-form-item>
        </div>

        <!-- 保存按钮 -->
        <div class="section">
          <el-form-item>
            <el-button type="primary" class="save-btn" @click="handleSave" :loading="saveLoading" size="medium">
              保 存
            </el-button>
            <el-button @click="handleReset" size="medium">重 置</el-button>
          </el-form-item>
        </div>

      </el-form>
    </el-card>
  </div>
</template>

<script>
import request from '@/api/index'

export default {
  name: 'SettingIndex',
  data() {
    const validatePhone = (rule, value, callback) => {
      if (value && !/^[\d\-+() ]{6,20}$/.test(value)) {
        callback(new Error('请输入有效的电话号码'))
      } else {
        callback()
      }
    }

    return {
      saveLoading: false,
      form: {
        shopName: '',
        logoUrl: '',
        servicePhone: '',
        workHours: '',
        defaultShippingFee: 10,
        freeShippingThreshold: 99,
        mchId: '',
        paySecret: ''
      },
      rules: {
        shopName: [{ required: true, message: '请输入商城名称', trigger: 'blur' }],
        servicePhone: [
          { required: true, message: '请输入客服电话', trigger: 'blur' },
          { validator: validatePhone, trigger: 'blur' }
        ],
        workHours: [{ required: true, message: '请输入工作时间', trigger: 'blur' }],
        defaultShippingFee: [{ required: true, type: 'number', min: 0, message: '请设置默认运费', trigger: 'blur' }],
        freeShippingThreshold: [{ required: true, type: 'number', min: 0, message: '请设置免邮门槛', trigger: 'blur' }],
        mchId: [{ required: true, message: '请输入微信支付商户号', trigger: 'blur' }],
        paySecret: [{ required: true, message: '请输入支付密钥', trigger: 'blur' }]
      }
    }
  },
  created() {
    this.fetchSettings()
  },
  methods: {
    fetchSettings() {
      request({
        url: '/api/admin/settings',
        method: 'get'
      }).then(res => {
        if (res.code === 0 && res.data) {
          this.form = { ...this.form, ...res.data }
        } else {
          this.$message.warning('API暂不可用，使用默认设置')
        }
      }).catch(() => {
        this.$message.warning('API暂不可用，使用默认设置')
      })
    },
    beforeLogoUpload(file) {
      const isImage = /^image\/(jpeg|png)$/.test(file.type)
      const isLt2M = file.size / 1024 / 1024 < 2

      if (!isImage) {
        this.$message.error('请上传JPG或PNG格式的图片')
        return false
      }
      if (!isLt2M) {
        this.$message.error('图片大小不能超过2MB')
        return false
      }
      return true
    },
    handleLogoUpload(options) {
      const file = options.file
      const reader = new FileReader()
      reader.readAsDataURL(file)
      reader.onload = () => {
        this.form.logoUrl = reader.result
        this.$message.success('Logo上传成功')
      }
      reader.onerror = () => {
        this.$message.error('Logo上传失败，请重试')
      }
    },
    handleSave() {
      this.$refs.settingForm.validate(valid => {
        if (!valid) return

        this.saveLoading = true
        request({
          url: '/api/admin/settings',
          method: 'put',
          data: this.form
        }).then(res => {
          if (res.code === 0) {
            this.$message.success('系统设置保存成功')
          } else {
            this.$message.error(res.message || '保存失败')
          }
        }).catch(() => {
          this.$message.error('保存失败，请重试')
        }).finally(() => {
          this.saveLoading = false
        })
      })
    },
    handleReset() {
      this.fetchSettings()
      this.$nextTick(() => {
        this.$refs.settingForm && this.$refs.settingForm.clearValidate()
      })
      this.$message.info('已重置为上次保存的设置')
    }
  }
}
</script>

